fn factorial(n: i32) -> Result<u128, &'static str> {
    if n < 0 {
        return Err("El número debe ser no negativo");
    }
    if n == 0 {
        return Ok(1);
    }
    factorial(n - 1).map(|res| n as u128 * res)
}

fn main() {
    let test_cases = [5, 0, -3];

    for &n in &test_cases {
        match factorial(n) {
            Ok(val) => println!("El factorial de {} es: {}", n, val),
            Err(e) => println!("Error al calcular factorial de {}: {}", n, e),
        }
    }
}
