const fetchWithRetry = async (url, options = {}, maxAttempts = 3) => {
  let lastError;

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      const response = await fetch(url, options);

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      lastError = error;
      console.warn(`Attempt ${attempt} failed: ${error.message}`);

      if (attempt < maxAttempts) {
        // Espera 1 segundo antes de reintentar (Exponential backoff opcional)
        await new Promise((resolve) => setTimeout(resolve, 1000));
      }
    }
  }

  throw new Error(`Request failed after ${maxAttempts} attempts. Last error: ${lastError.message}`);
};

// Ejemplo de uso:
(async () => {
  const API_URL = 'https://jsonplaceholder.typicode.com/posts/1';

  try {
    const data = await fetchWithRetry(API_URL);
    console.log('Success:', data);
  } catch (error) {
    console.error('Final Failure:', error.message);
  }
})();
